import { mkdir, writeFile } from 'node:fs/promises'
import { dirname, join } from 'node:path'
import { fileURLToPath } from 'node:url'

const rootDirectory = dirname(fileURLToPath(new URL('../package.json', import.meta.url)))
const serviceWorkerPath = join(rootDirectory, 'public', 'sw.js')

const developmentServiceWorker = `/* Development-only service worker.
 * The production worker is generated by next build through Serwist.
 * In local dev, this file replaces any stale generated worker so localhost
 * does not precache old hashed Next.js chunks.
 */

self.addEventListener('install', () => {
  self.skipWaiting()
})

self.addEventListener('activate', (event) => {
  event.waitUntil((async () => {
    try {
      const cacheNames = await caches.keys()
      await Promise.all(cacheNames.map((cacheName) => caches.delete(cacheName)))
      await self.clients.claim()
      await self.registration.unregister()

      const windowClients = await self.clients.matchAll({ type: 'window', includeUncontrolled: true })
      for (const client of windowClients) {
        client.navigate(client.url)
      }
    } catch {
      // Best-effort dev cleanup only. Stale worker failures should not break local pages.
    }
  })())
})
`

await mkdir(dirname(serviceWorkerPath), { recursive: true })
await writeFile(serviceWorkerPath, developmentServiceWorker)
